+    #[test]
+    fn capture_fp_result_stores_bits() {
+        let mut trace = NondeterminismTrace::new("fp-session");
+        let value = 1.5_f64;
+        trace.capture_fp_result(value, 100, "arith");
+        assert_eq!(trace.events.len(), 1);
